15	export function processScenario(scenario: any): any {
16	  const step = scenario.steps[0];
17	  let basePremium = 0;
18	  const typeCounts: Record<string, number> = {};
19	  for (const item of step.items) {
20	    typeCounts[item.type] = (typeCounts[item.type] || 0) + 1;
21	  }
22	  for (const [type, count] of Object.entries(typeCounts)) {
23	    const isComponentType = COMPONENT_TYPES.has(type);
24	    const formsBlockOf3 = count === 3 && isComponentType;
25	    if (formsBlockOf3) {
26	      basePremium += BLOCK_OF_3_PRICE;
27	    } else {
28	      basePremium += count * BASE_PREMIUM[type];
29	    }
30	  }
31	  let curseSurcharge = 0;
32	  for (const item of step.items) {
33	    if (item.cursed) {
34	      curseSurcharge += BASE_PREMIUM[item.type] * 0.5;
35	    }
36	  }
37	  const firstInsuranceSurcharge = basePremium * FIRST_INSURANCE_RATE;
38	  const premium = basePremium + curseSurcharge + firstInsuranceSurcharge + PROCESSING_FEE;
39	  return { results: [{ premium }] };
40	}
